mapper.select:
select ( case when substr(#{param1}, 1, 7) = substr(#{param2}, 1, 7) then substr(record_time, 1, 10) else substr(record_time, 1, 7) end ) time_name, sum(case when transaction_type = 1 then amount else 0 end) invoice_amount, sum(case when transaction_type = 2 then amount else 0 end) spending_amount, sum(case when transaction_type = 1 then amount else 0 end) - sum(case when transaction_type = 2 then amount else 0 end) balance_amount from t_asset_transaction
and record_time >= #{param1}
and record_time < #{param2}
group by ( case when substr(#{param1}, 1, 7) = substr(#{param2}, 1, 7) then substr(record_time, 1, 10) else substr(record_time, 1, 7) end ) order by ( case when substr(#{param1}, 1, 7) = substr(#{param2}, 1, 7) then substr(record_time, 1, 10) else substr(record_time, 1, 7) end )

select (select d.`value` from t_sys_dict d where d.type = 'invoice_type' and d.`code` = invoice_type limit 1) text, sum(amount) value from t_asset_transaction
and record_time >= #{param1}
and record_time < #{param2}
and transaction_type = 2
group by invoice_type order by invoice_type

select (select d.`value` from t_sys_dict d where d.type = 'spending_type' and d.`code` = spending_type limit 1) text, sum(amount) value from t_asset_transaction
and record_time >= #{param1}
and record_time < #{param2}
and transaction_type = 2
group by spending_type order by spending_type

select (select d.`value` from t_sys_dict d where d.type = 'invoice_type' and d.`code` = invoice_type limit 1) text, sum(amount) value from t_asset_transaction
and record_time >= #{param1}
and record_time < #{param2}
and transaction_type = 1
group by invoice_type order by invoice_type
